  NumberFormatStyle(number) {
    let result = formatNumber(Number(number), "en-US", "1.3-3");
    return result;
  }

  ChangeCheckBoxValue(value) {
    if (value == true) {
      return 1;
    } else if (value == false) {
      return 0;
    }
  }

  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }

